package com.jeestudio.bpm.modules.${table.module}.controller;

import com.jeestudio.bpm.controller.base.BaseController;
import com.jeestudio.bpm.modules.${table.module}.service.${ClassName}ServiceI;
import com.jeestudio.bpm.service.common.ZformService;
import com.jeestudio.bpm.service.system.SecLogService;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("${'$'}{adminPath}/${table.module}/${table.javaInstanceName}")
@Slf4j
public class ${table.javaClassName}Controller extends BaseController {

    @Autowired
    private SecLogService secLogService;

    @Autowired
    ZformService zformService;

    @Autowired
    ${table.javaClassName}ServiceI ${table.javaInstanceName}Service;

}
